class _JsonFileStore:
    """Minimal AsyncKeyValue store that persists tokens as JSON files in a directory.

    Avoids FileTreeStore's limitation of using keys as filesystem paths, which
    breaks when keys are URLs containing slashes.
    """

    def __init__(self, path: Path) -> None:
        self._path = path
        self._path.mkdir(parents=True, exist_ok=True)

    def _file(self, collection: str) -> Path:
        safe = hashlib.sha256(collection.encode()).hexdigest()[:16]
        return self._path / f"{safe}.json"

    def _load(self, collection: str) -> dict:
        f = self._file(collection)
        return json.loads(f.read_text()) if f.exists() else {}

    def _save(self, collection: str, data: dict) -> None:
        self._file(collection).write_text(json.dumps(data))

    async def get(self, key: str, *, collection: str | None = None) -> dict[str, Any] | None:
        return self._load(collection or "default").get(key)

    async def ttl(self, key: str, *, collection: str | None = None) -> tuple[dict[str, Any] | None, float | None]:
        return self._load(collection or "default").get(key), None

    async def put(self, key: str, value: Mapping[str, Any], *, collection: str | None = None, ttl: Any = None) -> None:
        data = self._load(collection or "default")
        data[key] = dict(value)
        self._save(collection or "default", data)

    async def delete(self, key: str, *, collection: str | None = None) -> bool:
        data = self._load(collection or "default")
        if key in data:
            del data[key]
            self._save(collection or "default", data)
            return True
        return False

    async def get_many(self, keys: list[str], *, collection: str | None = None) -> list[dict[str, Any] | None]:
        data = self._load(collection or "default")
        return [data.get(k) for k in keys]


# Auth resolution:
#   --oauth flag or ATLAN_AUTH=oauth  →  OAuth regardless of ATLAN_API_KEY
#   ATLAN_BASE_URL + ATLAN_API_KEY    →  Bearer auth against {base_url}/mcp/api-key
#   ATLAN_BASE_URL (no API key)       →  OAuth against {base_url}/mcp
_base_url = os.environ.get("ATLAN_BASE_URL", "").rstrip("/")
_api_key = os.environ.get("ATLAN_API_KEY")
_force_oauth = os.environ.get("ATLAN_AUTH", "").lower() == "oauth"
if "--oauth" in sys.argv:
    _force_oauth = True
    sys.argv.remove("--oauth")

if not _base_url:
    raise SystemExit("Error: ATLAN_BASE_URL must be set (e.g. https://your-tenant.atlan.com)")

_token_store = _JsonFileStore(Path.home() / ".atlan" / "mcp-tokens")

if _api_key and not _force_oauth:
    CLIENT_SPEC = f"{_base_url}/mcp/api-key"
    _auth = BearerAuth(_api_key)
else:
    CLIENT_SPEC = f"{_base_url}/mcp"
    _auth = OAuth(mcp_url=CLIENT_SPEC, token_storage=_token_store)

app = cyclopts.App(name="mcp.atlan.com", help="CLI for mcp.atlan.com MCP server")
call_tool_app = cyclopts.App(name="call-tool", help="Call a tool on the server")
app.command(call_tool_app)

console = Console()


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------


def _print_tool_result(result):
    if result.is_error:
        for block in result.content:
            if isinstance(block, mcp.types.TextContent):
                console.print(f"[bold red]Error:[/bold red] {block.text}")
            else:
                console.print(f"[bold red]Error:[/bold red] {block}")
        sys.exit(1)

    if result.structured_content is not None:
        console.print_json(json.dumps(result.structured_content))
        return

    for block in result.content:
        if isinstance(block, mcp.types.TextContent):
            console.print(block.text)
        elif isinstance(block, mcp.types.ImageContent):
            size = len(block.data) * 3 // 4
            console.print(f"[dim][Image: {block.mimeType}, ~{size} bytes][/dim]")
        elif isinstance(block, mcp.types.AudioContent):
            size = len(block.data) * 3 // 4
            console.print(f"[dim][Audio: {block.mimeType}, ~{size} bytes][/dim]")


async def _call_tool(tool_name: str, arguments: dict) -> None:
    # Filter out None values and empty lists (defaults for optional array params)
    filtered = {
        k: v
        for k, v in arguments.items()
        if v is not None and (not isinstance(v, list) or len(v) > 0)
    }
    async with Client(CLIENT_SPEC, auth=_auth) as client:
        result = await client.call_tool(tool_name, filtered, raise_on_error=False)
        _print_tool_result(result)
        if result.is_error:
            sys.exit(1)


